/**
 * PATCH /users/:id/email
 *
 * Updates a user's email address.
 *
 * @param {object} userRepository - Injected UserRepository with:
 *   - findById(id): Promise<User|null>
 *   - findByEmail(email): Promise<User|null>
 *   - updateEmail(id, email): Promise<User>
 * @returns Express route handler
 */
function makePatchUserEmailHandler(userRepository) {
  return async function patchUserEmail(req, res) {
    const { id } = req.params;
    const { email } = req.body;

    // AC3: Validate email format
    if (!isValidEmail(email)) {
      return res.status(400).json({
        error: {
          code: 'INVALID_EMAIL_FORMAT',
          message: 'The provided email address is not valid.',
        },
      });
    }

    // AC4: Verify user exists
    const existingUser = await userRepository.findById(id);
    if (!existingUser) {
      return res.status(404).json({
        error: {
          code: 'USER_NOT_FOUND',
          message: `No user found with id ${id}.`,
        },
      });
    }

    // AC5: Idempotent — same email, no change needed
    if (existingUser.email === email) {
      return res.status(200).json(existingUser);
    }

    // AC2: Email already in use by another user
    const userWithEmail = await userRepository.findByEmail(email);
    if (userWithEmail) {
      return res.status(409).json({
        error: {
          code: 'EMAIL_ALREADY_IN_USE',
          message: 'That email address is already associated with another account.',
        },
      });
    }

    // AC1: Perform the update
    const updatedUser = await userRepository.updateEmail(id, email);
    return res.status(200).json(updatedUser);
  };
}

/**
 * Validates an email address using RFC 5322-inspired regex.
 * Rejects empty/missing values and malformed strings like "not-an-email".
 */
function isValidEmail(email) {
  if (!email || typeof email !== 'string') return false;
  // Standard email regex: local@domain.tld
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return EMAIL_RE.test(email.trim());
}

module.exports = { makePatchUserEmailHandler, isValidEmail };

