const { makePatchUserEmailHandler, isValidEmail } = require('./handler');

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Build a minimal mock Express response with chainable status/json */
function makeRes() {
  const res = {};
  res.status = jest.fn().mockReturnValue(res);
  res.json = jest.fn().mockReturnValue(res);
  return res;
}

/** Build a mock UserRepository with controllable return values */
function makeRepo({ findByIdResult = null, findByEmailResult = null, updateEmailResult = null } = {}) {
  return {
    findById: jest.fn().mockResolvedValue(findByIdResult),
    findByEmail: jest.fn().mockResolvedValue(findByEmailResult),
    updateEmail: jest.fn().mockResolvedValue(updateEmailResult),
  };
}

const EXISTING_USER = { id: 'u1', email: 'alice@example.com', name: 'Alice' };
const UPDATED_USER  = { id: 'u1', email: 'alice-new@example.com', name: 'Alice' };

// ---------------------------------------------------------------------------
// AC1 — Happy path: valid user, valid new email → 200 + updated user
// ---------------------------------------------------------------------------

describe('AC1 — successful email update', () => {
  it('returns 200 with the updated user object', async () => {
    const repo = makeRepo({ findByIdResult: EXISTING_USER, updateEmailResult: UPDATED_USER });
    const handler = makePatchUserEmailHandler(repo);
    const req = { params: { id: 'u1' }, body: { email: 'alice-new@example.com' } };
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(200);
    expect(res.json).toHaveBeenCalledWith(UPDATED_USER);
    expect(repo.updateEmail).toHaveBeenCalledWith('u1', 'alice-new@example.com');
  });
});

// ---------------------------------------------------------------------------
// AC2 — Email already in use → 409 EMAIL_ALREADY_IN_USE
// ---------------------------------------------------------------------------

describe('AC2 — email already in use by another user', () => {
  it('returns 409 with EMAIL_ALREADY_IN_USE', async () => {
    const otherUser = { id: 'u2', email: 'taken@example.com' };
    const repo = makeRepo({ findByIdResult: EXISTING_USER, findByEmailResult: otherUser });
    const handler = makePatchUserEmailHandler(repo);
    const req = { params: { id: 'u1' }, body: { email: 'taken@example.com' } };
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(409);
    expect(res.json).toHaveBeenCalledWith(
      expect.objectContaining({ error: expect.objectContaining({ code: 'EMAIL_ALREADY_IN_USE' }) })
    );
    expect(repo.updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC3 — Invalid email format → 400 INVALID_EMAIL_FORMAT
// ---------------------------------------------------------------------------

describe('AC3 — invalid email format', () => {
  const invalidEmails = [
    'not-an-email',
    'missing@tld',
    '@nodomain.com',
    'spaces in@email.com',
    '',
    null,
    undefined,
  ];

  test.each(invalidEmails)('returns 400 for email: %s', async (badEmail) => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);
    const req = { params: { id: 'u1' }, body: { email: badEmail } };
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(400);
    expect(res.json).toHaveBeenCalledWith(
      expect.objectContaining({ error: expect.objectContaining({ code: 'INVALID_EMAIL_FORMAT' }) })
    );
    // Should short-circuit before hitting the repo
    expect(repo.findById).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC4 — User ID not found → 404 USER_NOT_FOUND
// ---------------------------------------------------------------------------

describe('AC4 — user not found', () => {
  it('returns 404 with USER_NOT_FOUND when findById returns null', async () => {
    const repo = makeRepo({ findByIdResult: null });
    const handler = makePatchUserEmailHandler(repo);
    const req = { params: { id: 'does-not-exist' }, body: { email: 'valid@example.com' } };
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(404);
    expect(res.json).toHaveBeenCalledWith(
      expect.objectContaining({ error: expect.objectContaining({ code: 'USER_NOT_FOUND' }) })
    );
    expect(repo.findByEmail).not.toHaveBeenCalled();
    expect(repo.updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC5 — Same email as current → 200 idempotent, no update performed
// ---------------------------------------------------------------------------

describe('AC5 — same email as current (idempotent)', () => {
  it('returns 200 with existing user and does NOT call updateEmail', async () => {
    const repo = makeRepo({ findByIdResult: EXISTING_USER });
    const handler = makePatchUserEmailHandler(repo);
    const req = { params: { id: 'u1' }, body: { email: EXISTING_USER.email } };
    const res = makeRes();

    await handler(req, res);

    expect(res.status).toHaveBeenCalledWith(200);
    expect(res.json).toHaveBeenCalledWith(EXISTING_USER);
    expect(repo.findByEmail).not.toHaveBeenCalled();
    expect(repo.updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// isValidEmail unit tests
// ---------------------------------------------------------------------------

describe('isValidEmail', () => {
  it.each([
    ['user@example.com', true],
    ['user+tag@sub.domain.org', true],
    ['not-an-email', false],
    ['missing@tld', false],
    ['@nodomain.com', false],
    ['', false],
    [null, false],
    [undefined, false],
  ])('isValidEmail(%s) → %s', (input, expected) => {
    expect(isValidEmail(input)).toBe(expected);
  });
});
